import { firefoxCompatibility } from './compatibility.js';
const shellQuote = (value) => `'${value.replaceAll("'", "'\\''")}'`;
export function generateMozconfig(config, firefoxVersion) {
    const compatibility = firefoxCompatibility(firefoxVersion);
    const lines = [
        `export ${compatibility.environment.appName}=${shellQuote(config.build.mode === 'full' ? config.browser.binaryName : 'firefox')}`,
        `ac_add_options ${compatibility.configure.appBasename}=${shellQuote(config.browser.name)}`,
    ];
    if (config.branding.enabled) {
        lines.push(`ac_add_options ${compatibility.configure.branding}=browser/branding/geckokit-${config.browser.binaryName}`);
    }
    if (config.build.mode === 'artifact') {
        lines.push(`ac_add_options ${compatibility.configure.artifactBuilds}`);
    }
    if (config.features.selected.includes('webdriver')) {
        lines.push(`ac_add_options ${compatibility.configure.disableWebdriver}`);
    }
    lines.push(`mk_add_options ${compatibility.make.objectDirectory}=@TOPSRCDIR@/obj-geckokit-${config.browser.binaryName}`, `mk_add_options ${compatibility.make.autoClobber}=1`);
    return `${lines.join('\n')}\n`;
}
